const sub = $json;
return [{ json: {
  clinic_id:               sub.clinic_id,
  is_subscription_renewal: true,
  purpose:                 'subscription_renewal',
  total:                   parseFloat(sub.price_omr) || 0,
  custom_expires_at:       new Date(Date.now() + 72 * 60 * 60 * 1000).toISOString(),
  _dunning_ctx:            sub
} }];

const dunningCtx = $('Prep Renewal Link Params').item.json._dunning_ctx;
const linkResult  = $json;
const paymentUrl  = (linkResult && linkResult.payment_url) ? linkResult.payment_url : null;
return [{ json: { ...dunningCtx, payment_url: paymentUrl } }];

const sub = $json;
const daysLeft = Math.max(1, Math.ceil((new Date(sub.grace_period_ends_at) - Date.now()) / (1000 * 60 * 60 * 24)));
const billingLabel = sub.billing_cycle === 'annual' ? 'سنوياً' : 'شهرياً';
const clinicName = sub.clinic_name_ar || sub.clinic_name || 'العيادة';
const urgency = daysLeft <= 2 ? '🚨 عاجل جداً' : '⚠️ تنبيه';
const paymentLine = sub.payment_url
  ? '

🔗 للدفع الفوري وتجديد الاشتراك:
' + sub.payment_url
  : '

للتجديد أو للاستفسار تواصلوا مع فريق طود مباشرة.';
const body = urgency + ': اشتراك نظام طود

عيادة ' + clinicName + '،

اشتراككم في نظام طود قد انتهت مدة دفعه.

📅 المتبقي قبل إيقاف الخدمة: ' + daysLeft + ' يوم
💰 مبلغ التجديد: ' + sub.price_omr + ' ريال عماني (' + billingLabel + ')' + paymentLine;
return [{ json: { ...sub, to: sub.clinic_phone, body, clinic_id: sub.clinic_id, _days_left: daysLeft } }];
